package org.apache.commons.lang3.reflect;

import java.lang.annotation.Annotation;
import java.lang.reflect.Executable;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.lang.reflect.TypeVariable;
import java.util.List;
import java.util.Map;

import org.apache.commons.lang3.ClassUtils;
import org.apache.commons.lang3.ClassUtils.Interfaces;

/**
 * Utilities for method lookup, matching and invocation. Extracted from MethodUtils to group invocation-related APIs.
 * Methods typically delegate to MethodUtilsCore or MethodInvoker as appropriate.
 *
 * @since 3.0 (extracted)
 */
public class MethodInvocationUtils {

    private MethodInvocationUtils() {
        // private utility class
    }

    public static Method getAccessibleMethod(final Class<?> cls, final Method method) {
        if (!MemberUtils.isPublic(method)) {
            return null;
        }
        // If the declaring class is public, we are done
        if (ClassUtils.isPublic(cls)) {
            return method;
        }
        final String methodName = method.getName();
        final Class<?>[] parameterTypes = method.getParameterTypes();
        // Check the implemented interfaces and subinterfaces
        final Method method2 = MethodUtilsCore.getAccessibleMethodFromInterfaceNest(cls, methodName, parameterTypes);
        // Check the superclass chain
        return method2 != null ? method2 : MethodUtilsCore.getAccessibleMethodFromSuperclass(cls, methodName, parameterTypes);
    }

    public static Method getAccessibleMethod(final Class<?> cls, final String methodName, final Class<?>... parameterTypes) {
        return getAccessibleMethod(getMethodObject(cls, methodName, parameterTypes));
    }

    public static Method getAccessibleMethod(final Method method) {
        return method != null ? getAccessibleMethod(method.getDeclaringClass(), method) : null;
    }

    public static <A extends Annotation> A getAnnotation(final Method method, final Class<A> annotationCls, final boolean searchSupers,
            final boolean ignoreAccess) {
        return MethodInvoker.getAnnotation(method, annotationCls, searchSupers, ignoreAccess);
    }

    public static Method getMatchingAccessibleMethod(final Class<?> cls, final String methodName, final Class<?>... requestTypes) {
        return MethodInvoker.getMatchingAccessibleMethod(cls, methodName, requestTypes);
    }

    public static Method getMatchingMethod(final Class<?> cls, final String methodName, final Class<?>... parameterTypes) {
        return MethodInvoker.getMatchingMethod(cls, methodName, parameterTypes);
    }

    public static Method getMethodObject(final Class<?> cls, final String name, final Class<?>... parameterTypes) {
        return MethodInvoker.getMethodObject(cls, name, parameterTypes);
    }

    public static List<Method> getMethodsListWithAnnotation(final Class<?> cls, final Class<? extends Annotation> annotationCls) {
        return getMethodsListWithAnnotation(cls, annotationCls, false, false);
    }

    public static List<Method> getMethodsListWithAnnotation(final Class<?> cls, final Class<? extends Annotation> annotationCls,
            final boolean searchSupers, final boolean ignoreAccess) {
        return MethodInvoker.getMethodsListWithAnnotation(cls, annotationCls, searchSupers, ignoreAccess);
    }

    public static Method[] getMethodsWithAnnotation(final Class<?> cls, final Class<? extends Annotation> annotationCls) {
        return getMethodsWithAnnotation(cls, annotationCls, false, false);
    }

    public static Method[] getMethodsWithAnnotation(final Class<?> cls, final Class<? extends Annotation> annotationCls,
            final boolean searchSupers, final boolean ignoreAccess) {
        return MethodInvoker.getMethodsWithAnnotation(cls, annotationCls, searchSupers, ignoreAccess);
    }

    public static Object invokeExactMethod(final Object object, final String methodName)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeExactMethod(object, methodName);
    }

    public static Object invokeExactMethod(final Object object, final String methodName, final Object... args)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeExactMethod(object, methodName, args);
    }

    public static Object invokeExactMethod(final Object object, final String methodName, final Object[] args, final Class<?>[] parameterTypes)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeExactMethod(object, methodName, args, parameterTypes);
    }

    public static Object invokeExactStaticMethod(final Class<?> cls, final String methodName, final Object... args)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeExactStaticMethod(cls, methodName, args);
    }

    public static Object invokeExactStaticMethod(final Class<?> cls, final String methodName, final Object[] args, final Class<?>[] parameterTypes)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeExactStaticMethod(cls, methodName, args, parameterTypes);
    }

    public static Object invokeMethod(final Object object, final boolean forceAccess, final String methodName)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeMethod(object, forceAccess, methodName);
    }

    public static Object invokeMethod(final Object object, final boolean forceAccess, final String methodName, final Object... args)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeMethod(object, forceAccess, methodName, args);
    }

    public static Object invokeMethod(final Object object, final boolean forceAccess, final String methodName, final Object[] args,
            final Class<?>[] parameterTypes) throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeMethod(object, forceAccess, methodName, args, parameterTypes);
    }

    public static Object invokeMethod(final Object object, final String methodName)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeMethod(object, methodName);
    }

    public static Object invokeMethod(final Object object, final String methodName, final Object... args)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeMethod(object, methodName, args);
    }

    public static Object invokeMethod(final Object object, final String methodName, final Object[] args, final Class<?>[] parameterTypes)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeMethod(object, methodName, args, parameterTypes);
    }

    public static Object invokeStaticMethod(final Class<?> cls, final String methodName, final Object... args)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeStaticMethod(cls, methodName, args);
    }

    public static Object invokeStaticMethod(final Class<?> cls, final String methodName, final Object[] args, final Class<?>[] parameterTypes)
            throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
        return MethodInvoker.invokeStaticMethod(cls, methodName, args, parameterTypes);
    }

    static Object[] toVarArgs(final Executable executable, final Object[] args)
            throws IllegalAccessException, InvocationTargetException, NoSuchMethodException {
        return MethodUtilsCore.toVarArgs(executable, args);
    }

    private static Object[] toVarArgs(final Object[] args, final Class<?>[] methodParameterTypes)
            throws IllegalAccessException, InvocationTargetException, NoSuchMethodException {
        return MethodUtilsCore.toVarArgs(args, methodParameterTypes);
    }

    public static int distance(final Class<?>[] fromClassArray, final Class<?>[] toClassArray) {
        return MethodUtilsCore.distance(fromClassArray, toClassArray);
    }

    public static java.util.List<Class<?>> getAllSuperclassesAndInterfaces(final Class<?> cls) {
        return MethodUtilsCore.getAllSuperclassesAndInterfaces(cls);
    }

    public static java.util.Set<Method> getOverrideHierarchy(final Method method, final Interfaces interfacesBehavior) {
        // Delegate to existing higher-level implementation in MethodUtils for override hierarchy
        return MethodUtils.getOverrideHierarchy(method, interfacesBehavior);
    }
}
